function createRenderer() {
  function clamp(value) { return Math.max(0, Math.min(1, value)); }
  function easeOut(value) { value = clamp(value); return 1 - Math.pow(1 - value, 3); }
  function easeInOut(value) { value = clamp(value); return value < 0.5 ? 4 * value * value * value : 1 - Math.pow(-2 * value + 2, 3) / 2; }
  function pulse(time, speed, phase) { return 0.5 + 0.5 * Math.sin(time * speed + phase); }
  function roundedRect(ctx, x, y, width, height, radius) {
    ctx.beginPath();
    ctx.moveTo(x + radius, y);
    ctx.lineTo(x + width - radius, y);
    ctx.quadraticCurveTo(x + width, y, x + width, y + radius);
    ctx.lineTo(x + width, y + height - radius);
    ctx.quadraticCurveTo(x + width, y + height, x + width - radius, y + height);
    ctx.lineTo(x + radius, y + height);
    ctx.quadraticCurveTo(x, y + height, x, y + height - radius);
    ctx.lineTo(x, y + radius);
    ctx.quadraticCurveTo(x, y, x + radius, y);
    ctx.closePath();
  }
  function render(time, context) {
    var ctx = context.mainContext;
    var width = context.width;
    var height = context.height;
    var intro = easeOut(time / 1.1);
    var product = easeOut((time - 0.8) / 1.4);
    var metrics = easeOut((time - 2.4) / 1.2);
    var workflow = easeOut((time - 4.1) / 1.25);
    var final = easeOut((time - 6.8) / 1.0);
    drawBackground(ctx, width, height, time);
    drawHeroText(ctx, width, height, time, intro, final);
    drawProductInterface(ctx, width, height, time, product, final);
    drawMetricCards(ctx, width, height, time, metrics, final);
    drawWorkflow(ctx, width, height, time, workflow, final);
    drawFinalCTA(ctx, width, height, time, final);
    drawProgress(ctx, width, height, time, 9);
  }
  function drawBackground(ctx, width, height, time) {
    var gradient = ctx.createLinearGradient(0, 0, width, height);
    gradient.addColorStop(0, '#030712');
    gradient.addColorStop(0.42, '#071A2F');
    gradient.addColorStop(0.75, '#15112B');
    gradient.addColorStop(1, '#1B1305');
    ctx.fillStyle = gradient;
    ctx.fillRect(0, 0, width, height);
    ctx.save();
    ctx.globalCompositeOperation = 'screen';
    var glowA = ctx.createRadialGradient(width * 0.78, height * 0.22, 20, width * 0.78, height * 0.22, 560);
    glowA.addColorStop(0, 'rgba(0,212,255,.42)');
    glowA.addColorStop(1, 'rgba(0,212,255,0)');
    ctx.fillStyle = glowA;
    ctx.fillRect(0, 0, width, height);
    var glowB = ctx.createRadialGradient(width * 0.18, height * 0.82, 20, width * 0.18, height * 0.82, 600);
    glowB.addColorStop(0, 'rgba(242,170,76,.32)');
    glowB.addColorStop(1, 'rgba(242,170,76,0)');
    ctx.fillStyle = glowB;
    ctx.fillRect(0, 0, width, height);
    ctx.restore();
    ctx.save();
    ctx.globalAlpha = 0.11;
    ctx.strokeStyle = '#DDF7FF';
    ctx.lineWidth = 1;
    var offset = (time * 24) % 88;
    for (var x = -240; x < width + 240; x += 88) {
      ctx.beginPath();
      ctx.moveTo(x + offset, 0);
      ctx.lineTo(x - 360 + offset, height);
      ctx.stroke();
    }
    for (var i = 0; i < 140; i++) {
      var px = (i * 139 + Math.sin(time * 0.6 + i) * 44 + width) % width;
      var py = (i * 71 + Math.cos(time * 0.5 + i * 0.3) * 36 + height) % height;
      ctx.fillStyle = i % 3 === 0 ? '#00D4FF' : i % 3 === 1 ? '#7BD88F' : '#F2AA4C';
      ctx.globalAlpha = 0.05 + (i % 5) * 0.025;
      ctx.beginPath();
      ctx.arc(px, py, 1.4 + (i % 3), 0, Math.PI * 2);
      ctx.fill();
    }
    ctx.restore();
  }
  function drawHeroText(ctx, width, height, time, intro, final) {
    ctx.save();
    ctx.globalAlpha = intro * (1 - final * 0.46);
    ctx.translate((1 - intro) * -70, 0);
    ctx.textAlign = 'left';
    ctx.fillStyle = '#FFFFFF';
    ctx.font = '900 88px Arial, sans-serif';
    ctx.fillText('Turn product updates', 118, 166);
    ctx.fillText('into launch videos.', 118, 266);
    var shine = ctx.createLinearGradient(118 + (time * 180) % 620, 0, 760 + (time * 180) % 620, 0);
    shine.addColorStop(0, '#00D4FF');
    shine.addColorStop(0.5, '#FFFFFF');
    shine.addColorStop(1, '#F2AA4C');
    ctx.fillStyle = shine;
    ctx.font = '900 30px Arial, sans-serif';
    ctx.fillText('One JSON. One render command. A polished MP4.', 124, 344);
    ctx.fillStyle = '#B8C7D9';
    ctx.font = '25px Arial, sans-serif';
    ctx.fillText('Designed for SaaS launches, changelogs, investor demos,', 124, 391);
    ctx.fillText('and AI-generated marketing workflows.', 124, 431);
    drawBadge(ctx, 124, 490, 'Launch Story', '#00D4FF');
    drawBadge(ctx, 318, 490, 'Metrics', '#7BD88F');
    drawBadge(ctx, 462, 490, 'CTA', '#F2AA4C');
    ctx.restore();
  }
  function drawBadge(ctx, x, y, label, color) {
    ctx.fillStyle = 'rgba(255,255,255,.08)';
    roundedRect(ctx, x, y, 154, 48, 24);
    ctx.fill();
    ctx.strokeStyle = color;
    ctx.lineWidth = 1.4;
    ctx.stroke();
    ctx.fillStyle = '#EEF6FF';
    ctx.font = '800 16px Arial, sans-serif';
    ctx.textAlign = 'center';
    ctx.fillText(label, x + 77, y + 31);
  }
  function drawProductInterface(ctx, width, height, time, amount, final) {
    var x = 925 + (1 - amount) * 220;
    var y = 122 + Math.sin(time * 0.7) * 8;
    ctx.save();
    ctx.globalAlpha = amount * (1 - final * 0.35);
    ctx.translate(x, y);
    ctx.rotate((-4 + Math.sin(time * 0.6) * 1.4) * Math.PI / 180);
    ctx.shadowColor = 'rgba(0,0,0,.56)';
    ctx.shadowBlur = 70;
    ctx.shadowOffsetY = 32;
    var shell = ctx.createLinearGradient(0, 0, 760, 620);
    shell.addColorStop(0, 'rgba(255,255,255,.2)');
    shell.addColorStop(1, 'rgba(255,255,255,.055)');
    ctx.fillStyle = shell;
    roundedRect(ctx, 0, 0, 760, 620, 40);
    ctx.fill();
    ctx.shadowBlur = 0;
    ctx.strokeStyle = 'rgba(255,255,255,.22)';
    ctx.lineWidth = 1;
    ctx.stroke();
    drawWindowBar(ctx, 0, 0, 760);
    drawDashboard(ctx, time, 42, 92);
    drawSidePanel(ctx, time, 520, 110);
    ctx.restore();
  }
  function drawWindowBar(ctx, x, y, width) {
    ctx.fillStyle = 'rgba(3,7,18,.42)';
    roundedRect(ctx, x + 22, y + 22, width - 44, 50, 18);
    ctx.fill();
    var colors = ['#FF5F57', '#FFBD2E', '#28C840'];
    for (var i = 0; i < 3; i++) {
      ctx.fillStyle = colors[i];
      ctx.beginPath();
      ctx.arc(x + 52 + i * 28, y + 47, 7, 0, Math.PI * 2);
      ctx.fill();
    }
    ctx.fillStyle = '#AEEBFF';
    ctx.font = '800 16px monospace';
    ctx.fillText('launch-dashboard.json', x + 145, y + 53);
  }
  function drawDashboard(ctx, time, x, y) {
    ctx.fillStyle = 'rgba(0,0,0,.24)';
    roundedRect(ctx, x, y, 440, 470, 26);
    ctx.fill();
    ctx.fillStyle = '#FFFFFF';
    ctx.font = '900 34px Arial, sans-serif';
    ctx.fillText('AstraOS 2.0', x + 32, y + 60);
    ctx.fillStyle = '#9FB4C9';
    ctx.font = '20px Arial, sans-serif';
    ctx.fillText('Launch performance forecast', x + 32, y + 96);
    var bars = [0.82, 0.64, 0.92, 0.55, 0.76, 0.88, 0.69];
    for (var i = 0; i < bars.length; i++) {
      var barX = x + 42 + i * 52;
      var barH = bars[i] * 170 * (0.86 + pulse(time, 2.2, i) * 0.14);
      var grad = ctx.createLinearGradient(0, y + 350 - barH, 0, y + 350);
      grad.addColorStop(0, i % 2 ? '#7BD88F' : '#00D4FF');
      grad.addColorStop(1, 'rgba(255,255,255,.12)');
      ctx.fillStyle = grad;
      roundedRect(ctx, barX, y + 350 - barH, 30, barH, 15);
      ctx.fill();
    }
    ctx.strokeStyle = 'rgba(255,255,255,.18)';
    ctx.beginPath();
    ctx.moveTo(x + 34, y + 374);
    ctx.lineTo(x + 398, y + 374);
    ctx.stroke();
    drawSparkline(ctx, time, x + 48, y + 414, 330, 44, '#F2AA4C');
  }
  function drawSidePanel(ctx, time, x, y) {
    var cards = [
      ['Activation', '+38%', '#00D4FF'],
      ['Revenue', '$1.2M', '#7BD88F'],
      ['Render time', '09.6s', '#F2AA4C']
    ];
    for (var i = 0; i < cards.length; i++) {
      var yPos = y + i * 134;
      ctx.fillStyle = 'rgba(255,255,255,.075)';
      roundedRect(ctx, x, yPos, 178, 108, 20);
      ctx.fill();
      ctx.strokeStyle = cards[i][2];
      ctx.globalAlpha = 0.8;
      ctx.stroke();
      ctx.globalAlpha = 1;
      ctx.fillStyle = '#A9BDD2';
      ctx.font = '17px Arial, sans-serif';
      ctx.fillText(cards[i][0], x + 22, yPos + 36);
      ctx.fillStyle = '#FFFFFF';
      ctx.font = '900 30px Arial, sans-serif';
      ctx.fillText(cards[i][1], x + 22, yPos + 76);
      ctx.fillStyle = cards[i][2];
      ctx.beginPath();
      ctx.arc(x + 145, yPos + 35, 8 + pulse(time, 4, i) * 4, 0, Math.PI * 2);
      ctx.fill();
    }
  }
  function drawSparkline(ctx, time, x, y, width, height, color) {
    ctx.strokeStyle = color;
    ctx.lineWidth = 3;
    ctx.beginPath();
    for (var i = 0; i <= 30; i++) {
      var px = x + (i / 30) * width;
      var py = y + height * 0.5 + Math.sin(i * 0.55 + time * 2) * height * 0.28 - i * 0.65;
      if (i === 0) ctx.moveTo(px, py); else ctx.lineTo(px, py);
    }
    ctx.stroke();
  }
  function drawMetricCards(ctx, width, height, time, amount, final) {
    var cards = [
      ['01', 'Script', 'AI drafts the launch angle', '#00D4FF'],
      ['02', 'Motion', 'Timeline drives every frame', '#7BD88F'],
      ['03', 'Export', 'Browser encodes final MP4', '#F2AA4C']
    ];
    for (var i = 0; i < cards.length; i++) {
      var x = 124 + i * 262;
      var y = 610 + (1 - amount) * 46 + Math.sin(time + i) * 4;
      ctx.save();
      ctx.globalAlpha = amount * (1 - final * 0.5);
      ctx.fillStyle = 'rgba(3,7,18,.58)';
      roundedRect(ctx, x, y, 232, 138, 24);
      ctx.fill();
      ctx.strokeStyle = cards[i][3];
      ctx.lineWidth = 1.4;
      ctx.stroke();
      ctx.fillStyle = cards[i][3];
      ctx.font = '900 19px Arial, sans-serif';
      ctx.fillText(cards[i][0], x + 24, y + 36);
      ctx.fillStyle = '#FFFFFF';
      ctx.font = '900 28px Arial, sans-serif';
      ctx.fillText(cards[i][1], x + 24, y + 74);
      ctx.fillStyle = '#AABBD0';
      ctx.font = '17px Arial, sans-serif';
      ctx.fillText(cards[i][2], x + 24, y + 108);
      ctx.restore();
    }
  }
  function drawWorkflow(ctx, width, height, time, amount, final) {
    var steps = ['JSON', 'Runtime', 'Canvas', 'WebCodecs', 'MP4'];
    ctx.save();
    ctx.globalAlpha = amount * (1 - final * 0.55);
    ctx.textAlign = 'center';
    for (var i = 0; i < steps.length; i++) {
      var x = 180 + i * 152;
      var y = 835;
      ctx.fillStyle = 'rgba(255,255,255,.09)';
      roundedRect(ctx, x - 58, y - 30, 116, 60, 15);
      ctx.fill();
      ctx.strokeStyle = i === 4 ? '#F2AA4C' : '#00D4FF';
      ctx.lineWidth = 1.3;
      ctx.stroke();
      ctx.fillStyle = '#F5FBFF';
      ctx.font = '800 17px Arial, sans-serif';
      ctx.fillText(steps[i], x, y + 6);
      if (i < steps.length - 1) {
        ctx.strokeStyle = 'rgba(255,255,255,.3)';
        ctx.beginPath();
        ctx.moveTo(x + 62, y);
        ctx.lineTo(x + 88, y);
        ctx.stroke();
        ctx.fillStyle = '#7BD88F';
        ctx.beginPath();
        ctx.arc(x + 62 + ((time * 60 + i * 18) % 26), y, 4, 0, Math.PI * 2);
        ctx.fill();
      }
    }
    ctx.restore();
  }
  function drawFinalCTA(ctx, width, height, time, amount) {
    ctx.save();
    ctx.globalAlpha = amount;
    ctx.fillStyle = 'rgba(3,7,18,' + (0.46 * amount) + ')';
    ctx.fillRect(0, 0, width, height);
    var glow = ctx.createRadialGradient(width / 2, height / 2, 20, width / 2, height / 2, 430);
    glow.addColorStop(0, 'rgba(242,170,76,.32)');
    glow.addColorStop(1, 'rgba(242,170,76,0)');
    ctx.fillStyle = glow;
    ctx.fillRect(0, 0, width, height);
    ctx.textAlign = 'center';
    ctx.fillStyle = '#FFFFFF';
    ctx.font = '900 78px Arial, sans-serif';
    ctx.fillText('Your launch video,', width / 2, 410);
    ctx.fillText('generated from code.', width / 2, 500);
    ctx.fillStyle = '#BDEFFF';
    ctx.font = '28px Arial, sans-serif';
    ctx.fillText('Replace the copy, colors, metrics, and UI panels with your own product.', width / 2, 558);
    ctx.fillStyle = '#F2AA4C';
    roundedRect(ctx, width / 2 - 154, 624, 308, 72, 22);
    ctx.fill();
    ctx.fillStyle = '#07111F';
    ctx.font = '900 23px Arial, sans-serif';
    ctx.fillText('Render the release', width / 2, 670);
    ctx.restore();
  }
  function drawProgress(ctx, width, height, time, duration) {
    ctx.save();
    ctx.fillStyle = 'rgba(255,255,255,.14)';
    roundedRect(ctx, 120, height - 72, width - 240, 12, 6);
    ctx.fill();
    var gradient = ctx.createLinearGradient(120, 0, width - 120, 0);
    gradient.addColorStop(0, '#00D4FF');
    gradient.addColorStop(0.55, '#7BD88F');
    gradient.addColorStop(1, '#F2AA4C');
    ctx.fillStyle = gradient;
    roundedRect(ctx, 120, height - 72, (width - 240) * clamp(time / duration), 12, 6);
    ctx.fill();
    ctx.restore();
  }
  return { render: render };
}
